   239→		}
   240→		diags = diags.Append(ctx.Hook(func(h Hook) (HookAction, error) {
   241→			return h.PostApply(n.Addr, addrs.NotDeposed, newState, err)
   242→		}))
   243→	}
   244→
   245→	return diags
